// // This module implements a 8-bit shift register with serial input and output. The shift register has an enable signal that, when low, allows the data to be shifted in on the falling edge of the clock. The shift register also has a reset signal that sets all bits to one when activated. Implement the functionality to shift bits to the right, with the new input bit being placed at the most significant bit (MSB).
module shift_register (
    input clk,
    input reset,
    input enable,
    input serial_in,
    output reg [7:0] parallel_out
);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            parallel_out <= 8'b0;
        end else if (enable) begin
            parallel_out <= {parallel_out[6:0], serial_in};
        end
    end
endmodule
